const fs = require('fs');
const path = require('path');

const dir = '/data/transcripts/onboarding';
const allFiles = fs.readdirSync(dir);
const filtered = allFiles.filter(f => f.endsWith('.txt') && f !== '.gitkeep');

// Derive account_id: "onboarding_claraai.txt" → "demo_claraai"
return filtered.map(filename => {
  const stem = path.basename(filename, '.txt');                 // e.g. "onboarding_claraai"
  const account_id = stem.replace(/^onboarding_/, 'demo_');    // → "demo_claraai"
  const content = fs.readFileSync(path.join(dir, filename), 'utf8')
    .replace(/^\uFEFF/, '').trim();
  return { json: { account_id, transcript: content, filename } };
});

return $input.all().map(item => {
  const raw = item.json.response || '';
  const account_id = item.json.account_id;
  try {
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (!jsonMatch) throw new Error('No JSON found');
    const updates = JSON.parse(jsonMatch[0]);
    return { json: { updates, account_id } };
  } catch(e) {
    return { json: { parse_error: true, error_message: e.message, raw_response: raw, account_id } };
  }
});

const fs = require('fs');

return $input.all().map(item => {
  if (item.json.parse_error) return item;

  const updates = item.json.updates;
  const account_id = item.json.account_id;

  // Load existing v1 memo
  const v1Path = `/outputs/accounts/${account_id}/v1/account_memo_v1.json`;
  let v1Memo = {};
  try {
    v1Memo = JSON.parse(fs.readFileSync(v1Path, 'utf8'));
  } catch(e) {
    return { json: { error: 'v1 memo not found — run Pipeline A first', path: v1Path, account_id } };
  }

  const changes = [];

  function applyUpdate(v1, upd, path = '') {
    for (const key of Object.keys(upd)) {
      const newVal = upd[key];
      const oldVal = v1[key];
      if (newVal === null || newVal === '' || (Array.isArray(newVal) && newVal.length === 0)) continue;
      if (typeof newVal === 'object' && !Array.isArray(newVal)) {
        if (!v1[key]) v1[key] = {};
        applyUpdate(v1[key], newVal, path + key + '.');
      } else {
        if (JSON.stringify(oldVal) !== JSON.stringify(newVal)) {
          changes.push({ field: path + key, from: oldVal, to: newVal });
          v1[key] = newVal;
        }
      }
    }
  }

  applyUpdate(v1Memo, updates);
  v1Memo.version = 'v2';
  v1Memo.source = 'onboarding_call';

  return { json: { v2Memo: v1Memo, changes, account_id } };
});

return $input.all().map(item => {
  if (item.json.error || item.json.parse_error) return item;

  const { v2Memo, changes, account_id } = item.json;
  const bh = v2Memo.business_hours || {};
  const er = v2Memo.emergency_routing_rules || {};

  const toArray = (val) => {
    if (!val) return [];
    if (Array.isArray(val)) return val;
    if (typeof val === 'string') return [val];
    return [];
  };

  const emergencyDef = toArray(v2Memo.emergency_definition).join(', ') || 'sprinkler leak, fire alarm';
  const constraints = toArray(v2Memo.integration_constraints);
  const erOrder = toArray(er.order);

  const prompt = `You are Clara, an AI receptionist for ${v2Memo.company_name || 'this company'}.

BUSINESS HOURS FLOW (${bh.days || 'Mon-Fri'}, ${bh.start || '8AM'}-${bh.end || '5PM'} ${bh.timezone || ''}):
1. Greet: "Thank you for calling ${v2Memo.company_name || 'us'}, this is Clara. How can I help you today?"
2. Listen to purpose. Collect name and callback number.
3. Transfer to the appropriate team.
4. If transfer fails after ${(v2Memo.call_transfer_rules || {}).timeout_seconds || 30} seconds: apologize, confirm callback, close politely.

AFTER HOURS FLOW:
1. Greet: "Thank you for calling ${v2Memo.company_name || 'us'}. You've reached us outside of business hours."
2. Ask the purpose of their call.
3. Ask: "Is this an emergency?"
4. IF EMERGENCY (${emergencyDef}):
   - Collect name, callback number, and site address immediately.
   - Attempt transfer to: ${er.primary || 'on-call technician'}.
   - Fallback order: ${JSON.stringify(erOrder)}.
   - If all transfers fail: "I wasn't able to reach the on-call team. I've captured your details and dispatched an alert. Someone will reach you very shortly."
5. IF NON-EMERGENCY:
   - Collect name, number, and brief description.
   - Confirm: "I've noted your request and someone will follow up during business hours."

RULES:
- Never mention function calls or tools to the caller.
- Only collect what is needed for routing.
- Do not ask more questions than necessary.
${constraints.length ? '- Constraints: ' + constraints.join('; ') : ''}`;

  const spec = {
    account_id,
    agent_name: `Clara - ${v2Memo.company_name || account_id}`,
    voice_style: 'professional, calm, empathetic',
    system_prompt: prompt,
    key_variables: {
      timezone: bh.timezone || '',
      business_hours: bh,
      office_address: v2Memo.office_address || '',
      emergency_routing: er
    },
    tool_invocation_placeholders: ['transfer_call', 'create_ticket', 'lookup_account'],
    call_transfer_protocol: v2Memo.call_transfer_rules || {},
    fallback_protocol: 'If all transfers fail, apologise, assure callback, log the attempt.',
    version: 'v2'
  };

  return { json: { spec, v2Memo, changes, account_id } };
});

const fs = require('fs');
const results = [];

for (const item of $input.all()) {
  if (item.json.error || item.json.parse_error) {
    results.push({ json: { skipped: true, reason: item.json.error || item.json.error_message } });
    continue;
  }

  const { spec, v2Memo, changes, account_id } = item.json;

  // Create v2 directory
  const dir = `/outputs/accounts/${account_id}/v2`;
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

  // Write v2 memo
  fs.writeFileSync(`${dir}/account_memo_v2.json`, JSON.stringify(v2Memo, null, 2), 'utf8');

  // Write v2 spec
  fs.writeFileSync(`${dir}/agent_spec_v2.json`, JSON.stringify(spec, null, 2), 'utf8');

  // Write changes.json
  const changelog = {
    account_id,
    from_version: 'v1',
    to_version: 'v2',
    updated_at: new Date().toISOString(),
    changes
  };
  fs.writeFileSync(`${dir}/changes.json`, JSON.stringify(changelog, null, 2), 'utf8');

  // Also write to top-level changelog folder
  const clDir = '/outputs/changelog';
  if (!fs.existsSync(clDir)) fs.mkdirSync(clDir, { recursive: true });
  fs.writeFileSync(`${clDir}/${account_id}_changes.json`, JSON.stringify(changelog, null, 2), 'utf8');

  results.push({ json: { account_id, saved: true, changes_count: changes.length } });
}

return results;
